1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ---------- Base premiums (single item, only processing fee added) ----------
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it("single sword → premium 105 G (100 base + 5 fee)", () => {
14	    const result = processScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
17	    });
18	    expect(result).toEqual({ results: [{ premium: 105 }] });
19	  });
20	  it("single amulet → premium 65 G (60 base + 5 fee)", () => {
21	    const result = processScenario({
22	      customer: { yearsWithMHPCO: 0 },
23	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
24	    });
25	    expect(result).toEqual({ results: [{ premium: 65 }] });
26	  });
27	  it.todo("single staff → premium 85 G (80 base + 5 fee)");
28	  it.todo("single potion → premium 45 G (40 base + 5 fee)");
29	  it.todo("single rune component → premium 30 G (25 base + 5 fee)");
30	  it.todo("single moonstone component → premium 30 G (25 base + 5 fee)");
31	
32	  // ---------- Component blocks of 3 alike ----------
33	  it.todo("2 runes → 50 G base premium (no block)");
34	  it.todo("3 runes → 60 G base premium (block applies)");
35	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
36	  it.todo("7 runes → 175 G base premium");
37	
38	  // ---------- 'Alike' components (❓ same type, not just family) ----------
39	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
40	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
41	
42	  // ---------- Individual premium modifiers ----------
43	  it.todo("cursed sword (steel, enchant 3) → 100 + 50 curse + 5 fee = 155 G");
44	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (100 + 30 + 5 = 135 G)");
45	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (105 G)");
46	  it.todo("sword enchant 5 and cursed → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");
47	  it.todo("long-standing customer (exactly 2 years) → 20% loyalty discount applies");
48	  it.todo("first insurance surcharge (10%) applies to each item in a quote");
49	
50	  // ---------- Multi-item modifier scope (❓ per-item vs policy-wide) ----------
51	  it.todo("policy with cursed sword + plain amulet → 210 G before fee = 215 G total (curse applies only to cursed item)");
52	
53	  // ---------- Rounding in MHPCO's favor ----------
54	  it.todo("premium yielding 197.5 G → 198 G (rounded up)");
55	  it.todo("payout yielding 350.5 G → 350 G (rounded down)");
56	
57	  // ---------- Integration examples ----------
58	  it.todo("newcomer (0 years) with cursed steel sword enchant 3 → premium 165 G");
59	  it.todo("long-standing customer (3 years), second contract, cursed steel sword enchant 7 → premium 160 G");
60	
61	  // ---------- Claim processing: standard reimbursement ----------
62	  it.todo("regular sword (steel, enchant 3), damage 500 G → payout 400 G (500 − 100 deductible)");
63	  it.todo("rune damage 200 G → payout 100 G (no special clause: 200 − 100 deductible)");
64	
65	  // ---------- Special clauses ----------
66	  it.todo("steel sword, enchant 9, damage 1000 G → payout 400 G (high-enchantment 50% then deductible)");
67	  it.todo("dragon-material sword, enchant 5, damage 800 G → payout 700 G (dragon: full, then deductible)");
68	  it.todo("dragon-material sword, enchant 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
69	  it.todo("dragon-material sword, enchant exactly 8, damage 1000 G → payout 400 G (high-enchantment wins)");
70	
71	  // ---------- Deductible per damage event ----------
72	  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 G (deductible per item)");
73	
74	  // ---------- Cap behaviour ----------
75	  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
76	  it.todo("cursed sword (premium 165 G) → cap 2000 G (based on unmodified insurance value)");
77	  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 G; block discount does not affect insurance sum");
78	  it.todo("sword policy (cap 2000), two successive 1500 G claims → first payout 1400 G remaining 600 G; second payout 600 G remaining 0 G");
79	
80	  // ---------- Multiple items of the same type ----------
81	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
82	  it.todo("dragon attack damaging both swords → each entry treated as separate damage with its own deductible");
83	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero, claim rejected");
84	
85	  // ---------- Edge cases ----------
86	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with stderr message");
87	  it.todo("claim references an item not part of the policy → CLI exits non-zero with stderr message");
88	  it.todo("claim damage entry with negative amount → CLI exits non-zero with stderr message");
89	});
