1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	};
6	
7	type Item = { type: string };
8	type QuoteStep = { op: "quote"; items: Item[] };
9	type Step = QuoteStep;
10	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
11	
12	const quotePremium = (items: Item[]): number =>
13	  items.reduce((sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0), 0) +
14	  PROCESSING_FEE;
15	
16	export const processScenario = (input: Scenario): unknown => {
17	  const results = input.steps.map((step) => ({
18	    premium: quotePremium(step.items),
19	  }));
20	  return { results };
21	};
